83:     public PluginScanResult initLoaders(Set<PluginSource> pluginSources, PluginDiscoveryMode discoveryMode) {
84:         PluginScanResult empty = new PluginScanResult(Collections.emptyList());
85:         PluginScanResult serviceLoadingScanResult;
86:         try {
87:             serviceLoadingScanResult = discoveryMode.serviceLoad() ?
88:                     new ServiceLoaderScanner().discoverPlugins(pluginSources) : empty;
89:         } catch (Throwable t) {
90:             throw new ConnectException(String.format(
91:                     "Unable to perform ServiceLoader scanning as requested by %s=%s. It may be possible to fix this issue by reconfiguring %s=%s",
92:                     WorkerConfig.PLUGIN_DISCOVERY_CONFIG, discoveryMode,
93:                     WorkerConfig.PLUGIN_DISCOVERY_CONFIG, PluginDiscoveryMode.ONLY_SCAN), t);
94:         }
95:         PluginScanResult reflectiveScanResult = discoveryMode.reflectivelyScan() ?
96:                 new ReflectionScanner().discoverPlugins(pluginSources) : empty;
97:         PluginScanResult scanResult = new PluginScanResult(Arrays.asList(reflectiveScanResult, serviceLoadingScanResult));
98:         maybeReportHybridDiscoveryIssue(discoveryMode, serviceLoadingScanResult, scanResult);
99:         delegatingLoader.installDiscoveredPlugins(scanResult);
100:         return scanResult;
101:     }
