103:     // visible for testing
104:     static void maybeReportHybridDiscoveryIssue(PluginDiscoveryMode discoveryMode, PluginScanResult serviceLoadingScanResult, PluginScanResult mergedResult) {
105:         SortedSet<PluginDesc<?>> missingPlugins = new TreeSet<>();
106:         mergedResult.forEach(missingPlugins::add);
107:         serviceLoadingScanResult.forEach(missingPlugins::remove);
108:         if (missingPlugins.isEmpty()) {
109:             if (discoveryMode == PluginDiscoveryMode.HYBRID_WARN || discoveryMode == PluginDiscoveryMode.HYBRID_FAIL) {
110:                 log.warn("All plugins have ServiceLoader manifests, consider reconfiguring {}={}",
111:                         WorkerConfig.PLUGIN_DISCOVERY_CONFIG, PluginDiscoveryMode.SERVICE_LOAD);
112:             }
113:         } else {
114:             String message = String.format(
115:                 "One or more plugins are missing ServiceLoader manifests may not be usable with %s=%s: %s%n" +
116:                         "Read the documentation at %s for instructions on migrating your plugins " +
117:                         "to take advantage of the performance improvements of %s mode.",
118:                             WorkerConfig.PLUGIN_DISCOVERY_CONFIG,
119:                     PluginDiscoveryMode.SERVICE_LOAD,
120:                     missingPlugins.stream()
121:                             .map(pluginDesc -> pluginDesc.location() + "\t" + pluginDesc.className() + "\t" + pluginDesc.type() + "\t" + pluginDesc.version())
122:                             .collect(Collectors.joining("\n", "[\n", "\n]")),
123:                     "https://kafka.apache.org/documentation.html#connect_plugindiscovery",
124:                     PluginDiscoveryMode.SERVICE_LOAD
125:             );
126:             if (discoveryMode == PluginDiscoveryMode.HYBRID_WARN) {
127:                 log.warn("{} To silence this warning, set {}={} in the worker config.",
128:                         message, WorkerConfig.PLUGIN_DISCOVERY_CONFIG, PluginDiscoveryMode.ONLY_SCAN);
129:             } else if (discoveryMode == PluginDiscoveryMode.HYBRID_FAIL) {
130:                 throw new ConnectException(String.format("%s To silence this error, set %s=%s in the worker config.",
131:                         message, WorkerConfig.PLUGIN_DISCOVERY_CONFIG, PluginDiscoveryMode.HYBRID_WARN));
132:             }
133:         }
134:     }
