203:     public static ClassLoader compareAndSwapLoaders(ClassLoader loader) {
204:         ClassLoader current = Thread.currentThread().getContextClassLoader();
205:         if (!current.equals(loader)) {
206:             Thread.currentThread().setContextClassLoader(loader);
207:         }
208:         return current;
209:     }
