211:     public ClassLoader compareAndSwapWithDelegatingLoader() {
212:         ClassLoader current = Thread.currentThread().getContextClassLoader();
213:         if (!current.equals(delegatingLoader)) {
214:             Thread.currentThread().setContextClassLoader(delegatingLoader);
215:         }
216:         return current;
217:     }
