219:     /**
220:      * Perform the following operations with a specified thread context classloader.
221:      * <p>
222:      * Intended for use in a try-with-resources block such as the following:
223:      * <pre>{@code
224:      * try (LoaderSwap loaderSwap = plugins.withClassLoader(loader)) {
225:      *     // operation(s) sensitive to the thread context classloader
226:      * }
227:      * }</pre>
228:      * After the completion of the try block, the previous context classloader will be restored.
229:      * @see Thread#getContextClassLoader()
230:      * @see LoaderSwap
231:      * @param loader ClassLoader to use as the thread context classloader
232:      * @return A {@link LoaderSwap} handle which restores the prior classloader on {@link LoaderSwap#close()}.
233:      */
234:     public LoaderSwap withClassLoader(ClassLoader loader) {
235:         ClassLoader savedLoader = compareAndSwapLoaders(loader);
236:         try {
237:             return new LoaderSwap(savedLoader);
238:         } catch (Throwable t) {
239:             compareAndSwapLoaders(savedLoader);
240:             throw t;
241:         }
242:     }
243: 
244:     /**
245:      * Wrap a {@link Runnable} such that it is performed with the specified thread context classloader
246:      * @see Thread#getContextClassLoader()
247:      * @param classLoader {@link ClassLoader} to use as the thread context classloader
248:      * @param operation {@link Runnable} which is sensitive to the thread context classloader
249:      * @return A wrapper {@link Runnable} which will execute the wrapped operation
250:      */
251:     public Runnable withClassLoader(ClassLoader classLoader, Runnable operation) {
252:         return () -> {
253:             try (LoaderSwap loaderSwap = withClassLoader(classLoader)) {
254:                 operation.run();
255:             }
256:         };
257:     }
258: 
259:     public Function<ClassLoader, LoaderSwap> safeLoaderSwapper() {
260:         return loader -> {
261:             if (!(loader instanceof PluginClassLoader)) {
262:                 loader = delegatingLoader;
263:             }
264:             return withClassLoader(loader);
265:         };
266:     }
