385:     public Class<? extends Connector> connectorClass(String connectorClassOrAlias, VersionRange range) throws VersionedPluginLoadingException {
386:         Class<? extends Connector> klass;
387:         try {
388:             klass = pluginClass(delegatingLoader, connectorClassOrAlias, Connector.class, range);
389:         } catch (ClassNotFoundException e) {
390:             List<PluginDesc<? extends Connector>> matches = new ArrayList<>();
391:             Set<PluginDesc<Connector>> connectors = connectors();
392:             for (PluginDesc<? extends Connector> plugin : connectors) {
393:                 Class<?> pluginClass = plugin.pluginClass();
394:                 String simpleName = pluginClass.getSimpleName();
395:                 if (simpleName.equals(connectorClassOrAlias)
396:                         || simpleName.equals(connectorClassOrAlias + "Connector")) {
397:                     matches.add(plugin);
398:                 }
399:             }
400: 
401:             if (matches.isEmpty()) {
402:                 throw new ConnectException(
403:                         "Failed to find any class that implements Connector and which name matches "
404:                                 + connectorClassOrAlias
405:                                 + ", available connectors are: "
406:                                 + connectors.stream().map(PluginDesc::toString).collect(Collectors.joining(", "))
407:                 );
408:             }
409:             if (matches.size() > 1) {
410:                 throw new ConnectException(
411:                         "More than one connector matches alias "
412:                                 + connectorClassOrAlias
413:                                 + ". Please use full package and class name instead. Classes found: "
414:                                 + connectors.stream().map(PluginDesc::toString).collect(Collectors.joining(", "))
415:                 );
416:             }
417: 
418:             PluginDesc<? extends Connector> entry = matches.get(0);
419:             klass = entry.pluginClass();
420:         }
421:         return klass;
422:     }
