460:     private Converter newConverter(AbstractConfig config, String classPropertyName, String versionPropertyName, ClassLoaderUsage classLoaderUsage) {
461:         if (!config.originals().containsKey(classPropertyName)) {
462:             // This configuration does not define the converter via the specified property name
463:             return null;
464:         }
465:         // Determine whether this is a key or value converter based upon the supplied property name ...
466:         final boolean isKeyConverter = WorkerConfig.KEY_CONVERTER_CLASS_CONFIG.equals(classPropertyName);
467: 
468:         // Configure the Converter using only the old configuration mechanism ...
469:         String configPrefix = classPropertyName + ".";
470:         Map<String, Object> converterConfig = config.originalsWithPrefix(configPrefix);
471: 
472:         log.debug("Configuring the {} converter with configuration keys:{}{}",
473:                 isKeyConverter ? "key" : "value", System.lineSeparator(), converterConfig.keySet());
474: 
475:         Converter plugin = newVersionedPlugin(config, classPropertyName, versionPropertyName,
476:                 Converter.class, classLoaderUsage, scanResult.converters());
477:         try (LoaderSwap loaderSwap = safeLoaderSwapper().apply(plugin.getClass().getClassLoader())) {
478:             plugin.configure(converterConfig, isKeyConverter);
479:         }
