558:     @SuppressWarnings({"unchecked", "rawtypes"})
559:     private <U> U newVersionedPlugin(
560:             AbstractConfig config,
561:             String classPropertyName,
562:             String versionPropertyName,
563:             Class basePluginClass,
564:             ClassLoaderUsage classLoaderUsage,
565:             SortedSet<PluginDesc<U>> availablePlugins
566:     ) {
567: 
568:         String version = versionPropertyName == null ? null : config.getString(versionPropertyName);
569:         VersionRange range = null;
570:         if (version != null) {
571:             try {
572:                 range = PluginUtils.connectorVersionRequirement(version);
573:             } catch (InvalidVersionSpecificationException e) {
574:                 throw new ConnectException(String.format("Invalid version range for %s: %s", classPropertyName, version), e);
575:             }
576:         }
577: 
578:         assert range == null || classLoaderUsage == ClassLoaderUsage.PLUGINS;
579: 
580:         Class<? extends U> klass = null;
581:         String basePluginClassName = basePluginClass.getSimpleName();
582:         switch (classLoaderUsage) {
583:             case CURRENT_CLASSLOADER:
584:                 // Attempt to load first with the current classloader, and plugins as a fallback.
585:                 klass = pluginClassFromConfig(config, classPropertyName, basePluginClass, availablePlugins);
586:                 break;
587:             case PLUGINS:
588:                 // Attempt to load with the plugin class loader, which uses the current classloader as a fallback
589: 
590:                 // if the config specifies the class name, use it, otherwise use the default which we can get from config.getClass
591:                 String classOrAlias = config.originalsStrings().get(classPropertyName);
592:                 if (classOrAlias == null) {
593:                     classOrAlias = config.getClass(classPropertyName) == null ? null : config.getClass(classPropertyName).getName();
594:                 }
595:                 try {
596:                     klass = pluginClass(delegatingLoader, classOrAlias, basePluginClass, range);
597:                 } catch (ClassNotFoundException e) {
598:                     throw new ConnectException(
599:                             "Failed to find any class that implements " + basePluginClassName + " and which name matches "
600:                                     + classOrAlias + ", available plugins are: "
601:                                     + pluginNames(availablePlugins)
602:                     );
603:                 }
604:                 break;
605:         }
606:         if (klass == null) {
607:             throw new ConnectException("Unable to initialize the " + basePluginClassName
608:                     + " specified in " + classPropertyName);
609:         }
610: 
611:         U plugin;
612:         try (LoaderSwap loaderSwap = withClassLoader(klass.getClassLoader())) {
613:             plugin = newPlugin(klass);
614:         }
615:         return plugin;
616:     }
