662:         } catch (ClassNotFoundException e) {
663:             String msg = String.format("Failed to find any class that implements %s and which "
664:                                        + "name matches %s", pluginKlass, klassName);
665:             throw new ConnectException(msg);
666:         }
667:         try (LoaderSwap loaderSwap = withClassLoader(klass.getClassLoader())) {
668:             plugin = newPlugin(klass);
